class DatePicker extends DateTimePicker
{
    public function hasTime(): bool
    {
        return false;
    }
}

if ($relationship instanceof BelongsToMany) {
    return $relationship->getQualifiedRelatedKeyName();
}

if ($relationship instanceof HasOneOrManyThrough) {
    return $relationship->getQualifiedForeignKeyName();
}

class MultiSelect extends Select
{
    public function isMultiple(): bool
    {
        return true;
    }
}

enum Behavior: string
{
    case Tap = 'tap';
    case Drag = 'drag';
    case Fixed = 'fixed';
    case Unconstrained = 'unconstrained';
    case SmoothSteps = 'smooth-steps';
}

if (! method_exists($tableConfiguration, 'configure')) {
    throw new LogicException("Table configuration class [{$tableConfiguration}] does not have a [configure(Table \$table): Table] method.");
}

class TimePicker extends DateTimePicker
{
    public function hasDate(): bool
    {
        return false;
    }
}

abstract class Component
{
    use Conditionable;
    use Configurable;
    use EvaluatesClosures;
    use Macroable;
    use Tappable;
}

class MediaHasBeenAddedEvent
{
    use SerializesModels;

    public function __construct(public Media $media) {}
}

if ($resolveUsing instanceof Model) {
    return $this->resolvedRelatedRecords[$state] = $resolveUsing;
}

if ($resolveUsing instanceof Collection) {
    return $this->resolvedRelatedRecords[$encodedState] = $resolveUsing;
}

function wrap($subject) {
    return new Wrapped($subject);
}

function pipe($subject) {
    return new Pipe($subject);
}

try {
    if (! $storage->exists($file)) {
        return null;
    }
} catch (UnableToCheckFileExistence $exception) {
    return null;
}

interface StateCast
{
    public function get(mixed $state): mixed;

    public function set(mixed $state): mixed;
}

interface Collapsible
{
    public function isCollapsible(): bool;

    public function isCollapsed(): bool;
}

interface Editable
{
    public function validate(mixed $input): void;

    public function updateState(mixed $state): mixed;
}

interface Wireable
{
    public function toLivewire();

    public static function fromLivewire($value);
}

if (blank($response->message())) {
    throw new LogicException('An authorization was denied without a message.');
}

if (! $resolver) {
    throw new LogicException('No function was passed to [authorizeIndividualRecords()].');
}

if (! ($this instanceof HasTable)) {
    throw new ActionNotResolvableException('Failed to resolve table action for Livewire component without the [' . HasTable::class . '] trait.');
}

if (! $this instanceof HasSchemas) {
    throw new ActionNotResolvableException('Failed to resolve action schema for Livewire component without the [' . InteractsWithSchemas::class . '] trait.');
}

if (! confirm(
    label: 'Would you like to create a form for a model?',
    default: false,
)) {
    return;
}

interface CanDisableOptions
{
    public function disableOptionWhen(bool | Closure $callback): static;
}

interface HasFileAttachmentProvider
{
    public function getFileAttachmentProvider(): ?FileAttachmentProvider;
}

interface HasBeforeChallengeHook
{
    public function beforeChallenge(Authenticatable $user): void;
}

interface FontProvider
{
    public function getHtml(string $family, ?string $url = null): Htmlable;
}

interface GlobalSearchProvider
{
    public function getResults(string $query): ?GlobalSearchResults;
}

interface LoadingIndicator
{
    public function toHtml(ComponentAttributeBag $attributes): string;
}

class CachedState
{
    public static ?array $cachedRoutes = null;
    public static ?array $cachedConfig = null;
}

class PostFormWithTypedProperties extends Form
{
    public ?string $title = null;

    public ?string $content = null;
}
